BEGIN;
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('arthroplastie_epaule', 'orthopedie', '{"fr": "Arthroplastie de l''épaule (TSA / PTI inversée)", "en": "Shoulder arthroplasty (TSA / reverse TSA)", "pt": "Artroplastia do ombro (PTU total / reversa)"}'::jsonb, '{"fr": ["prothèse épaule", "TSA", "RSA", "prothèse totale inversée épaule", "arthroplastie gléno-humérale"], "en": ["shoulder replacement", "TSA", "reverse shoulder arthroplasty", "RSA"], "pt": ["prótese ombro", "artroplastia ombro"]}'::jsonb, '{"quick": {"fr": {"preop": ["Evaluation neurologique membre supérieur de base (déficits moteur/sensitif, plexus brachial)", "Bilan cardiovasculaire si position beach chair (risque hypotension cérébrale +++)", "Bloc interscalène préopératoire : analgésie optimale, réduction morphine postop (ASRA recommandé)", "Contre-indication relative bloc interscalène : pneumopathie controlatérale, parésie phrénique connue", "Groupage + RAI — saignement modéré (200-500 mL attendu)"], "intraop": ["Position beach chair (30-45°) : protéger tête/nuque, surveiller PA radiale AVANT installation", "PA invasive systématique (artère radiale) : maintenir PAM > 70 mmHg au niveau du conduit auditif", "AG ou bloc interscalène + sédation selon préférence et comorbidités", "Si AG : TIVA (propofol + remifentanil) ou halogéné — éviter protoxyde d''azote", "Attention brachial plexus stretch : vérifier position tête/épaule après installation", "Antibioprophylaxie : cefazoline 2g IV (vancomycine si allergie)", "Garrot pneumatique non utilisé (site trop proximal)"], "postop": ["Analgésie multimodale : bloc interscalène continu (ropivacaine 0.2%) 48h + paracetamol + AINS", "Sans bloc : paracetamol + AINS + morphine titrée IV", "Immobilisation coude au corps 4-6 semaines (écharpe)", "Surveillance neurologique postopératoire : déficit sensitif/moteur plexus brachial", "Kinésithérapie précoce guidée selon protocole chirurgien"], "red_flags": ["Hypotension peropératoire en beach chair (PAM < 60 au niveau cérébral) : risque AVC/ischémie cervicale — noradrenaline prete", "Paralysie phrénique (bloc interscalène 100%) : désaturation si pneumopathie controlatérale — SpO2 continue", "Lésion plexus brachial peropératoire (traction épaule) : scanner + EMG urgents", "Embolie cimenteuse (si ciment utilisé) : hypotension brutale + hypoxie — remplissage + vasopresseurs"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction"}, {"drug_id": "rocuronium", "indication_tag": "intubation"}, {"drug_id": "sugammadex", "indication_tag": "reversal"}, {"drug_id": "remifentanil", "indication_tag": "analgesie_TIVA"}, {"drug_id": "noradrenaline", "indication_tag": "PAM_beach_chair"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "ketorolac", "indication_tag": "analgesie"}, {"drug_id": "ondansetron", "indication_tag": "PONV"}, {"drug_id": "dexamethasone", "indication_tag": "PONV"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}]}}, "deep": {"fr": {"clinical": ["En beach chair, la PAM doit être maintenue > 70 mmHg au niveau du conduit auditif externe — corriger pour la différence hydrostatique (environ -15 mmHg par rapport au bras).", "Le bloc interscalène entraîne une paralysie phrénique ipsilatérale dans 100% des cas — évaluer la réserve respiratoire avant.", "La PTI inversée (reverse TSA) est indiquée chez le sujet âgé avec coiffe des rotateurs détruite — saignement plus important qu''une TSA standard.", "ERAS épaule : mobilisation précoce J1, bloc continu 48h, pas de morphine systématique."], "pitfalls": ["Ne pas surveiller la PA au poignet sans corriger la différence hydrostatique en beach chair — risque de sous-estimer la pression cérébrale.", "Bloc interscalène bilatéral : formellement contre-indiqué (double paralysie phrénique).", "Position beach chair > 2h : risque rare mais grave d''ischémie cérébrale — surveillance NIRS si disponible."], "references": [{"source": "ASRA — Regional Anesthesia for Shoulder Surgery", "year": 2022, "note": "Interscalene block recommendations"}, {"source": "SFAR — Arthroplasties", "year": 2020, "note": "Protocole anesthésie arthroplastie épaule"}, {"source": "ASES/SECEC — Shoulder Arthroplasty Guidelines", "year": 2021, "note": "Outcomes et technique"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('fracture_femur_diaphysaire', 'orthopedie', '{"fr": "Fracture diaphysaire du fémur (enclouage centromédullaire)", "en": "Femoral shaft fracture (intramedullary nailing)", "pt": "Fratura diafisária do fémur (encavilhamento intramedular)"}'::jsonb, '{"fr": ["fracture fémur", "clou centromédullaire fémur", "ECM fémur", "fracture milieu de cuisse"], "en": ["femur fracture", "femoral nailing", "IM nail femur"], "pt": ["fratura fémur", "encavilhamento femoral"]}'::jsonb, '{"quick": {"fr": {"preop": ["Bilan traumatologique complet : exclure lésions associées (bassin, genou, rachis, thorax)", "Evaluation hémodynamique : fracture fémur = 1-2L de saignement interne possibles", "NFS, groupage + RAI, hémostase, ionogramme, lactates si choc", "Bloc fémoral ou FICB (fascia iliaca compartment block) en urgence pour antalgique préop", "Traction provisoire si fracture instable (réduction douleur + spasme)"], "intraop": ["Table de traction orthopédique (table de Tasserit) : vérifier pression périnée et pied controlatéral", "Position décubitus dorsal ou latéral selon technique chirurgicale", "AG + IOT (rachianesthésie possible si patient stable et fracture isolée)", "Cathetère artériel si instabilité hémodynamique ou polytraumatisme", "Risque embolie graisseuse lors de l''alésage : hypoxie + tachycardie + pétéchies", "Transfusion si Hb < 8 g/dL (ou < 10 si cardiopathie) — cell salvage si disponible", "Antibioprophylaxie : cefazoline 2g IV avant incision"], "postop": ["Analgésie : paracetamol + AINS + morphine titrée — bloc fémoral continu si disponible", "Mobilisation précoce J1 (sauf complications) — ERAS fracture", "Thromboprophylaxie HBPM dès J0 soir si hémostase satisfaisante", "Surveillance compartiment : douleurs à l''étirement passif + tension cuisse = urgence", "Surveiller NFS à H6-H12 (estimation saignement perop)"], "red_flags": ["Syndrome de loge (compartiment) : douleurs intenses + engourdissement + tension musculaire — fasciotomie urgente", "Embolie graisseuse (6-72h post-fracture) : triade hypoxie + troubles neurologiques + pétéchies — O2 + soins de support", "Choc hémorragique (saignement fémoral ++ si fracture ouverte) : remplissage + transfusion + hémostase chirurgicale", "Compression nerf sciatique ou fémoral à la table de traction — vérifier position périodiquement"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction"}, {"drug_id": "rocuronium", "indication_tag": "intubation"}, {"drug_id": "sugammadex", "indication_tag": "reversal"}, {"drug_id": "sufentanil", "indication_tag": "analgesie_perop"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "ketorolac", "indication_tag": "analgesie"}, {"drug_id": "morphine", "indication_tag": "analgesie_postop"}, {"drug_id": "noradrenaline", "indication_tag": "hypotension"}, {"drug_id": "acide_tranexamique", "indication_tag": "antifibrinolytique"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}]}}, "deep": {"fr": {"clinical": ["La fracture diaphysaire du fémur est une urgence chirurgicale (idéalement < 24h) — chaque heure de retard augmente le risque d''embolie graisseuse et de choc.", "Le FICB (fascia iliaca compartment block) est une technique simple et efficace pour l''antalgie préopératoire — réduction des besoins en morphine aux urgences.", "L''embolie graisseuse survient surtout lors de l''alésage médullaire (release de graisse et de microthrombi) — hypoxie + choc dans les cas sévères.", "La table de traction expose au risque de compression du périnée (nerf pudendal) et du pied controlatéral."], "pitfalls": ["Ne pas sous-estimer le saignement interne (cuisse peut contenir 1-2L sans signe externe évident).", "L''alésage médullaire peut provoquer une embolie graisseuse brutale — surveiller SpO2 et ETCO2 lors de cette étape.", "Syndrome des loges de la cuisse : rare mais possible — surveiller systématiquement en postop."], "references": [{"source": "AO Foundation — Femoral Shaft Fractures", "year": 2023, "note": "Technique enclouage centromédullaire"}, {"source": "SFAR — Traumatologie et anesthésie", "year": 2021, "note": "Prise en charge anesthésique fractures membres inférieurs"}, {"source": "NICE — Major Trauma", "year": 2022, "note": "Damage control and fracture management"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
INSERT INTO public.procedures (id, specialty, titles, synonyms, content, is_pro)
VALUES ('arthrodese_lombaire', 'neurochirurgie', '{"fr": "Arthrodèse lombaire (PLIF / TLIF / ALIF)", "en": "Lumbar spinal fusion (PLIF / TLIF / ALIF)", "pt": "Artrodese lombar (PLIF / TLIF / ALIF)"}'::jsonb, '{"fr": ["fusion lombaire", "arthrodèse rachis lombaire", "PLIF", "TLIF", "ALIF", "spondylodèse lombaire"], "en": ["lumbar fusion", "spinal fusion", "PLIF", "TLIF"], "pt": ["artrodese lombar", "fusão lombar", "espondilodese"]}'::jsonb, '{"quick": {"fr": {"preop": ["Evaluation neurologique de base : déficits radiculaires, niveau sensitivo-moteur (documentation)", "Bilan cardiovasculaire si terrain vasculaire (ALIF — dissection aortique possible)", "NFS, groupage + RAI, hémostase — saignement attendu 500-1500 mL selon niveaux", "Discuter cell salvage si arthrodèse multi-étagée (≥ 3 niveaux)", "Corticostéroïdes préopératoires si oedème radiculaire préexistant"], "intraop": ["AG + IOT — position ventrale (DV) sur billots ou cadre de Wilson", "Protections pression scrupuleuses : yeux (risque cécité), genoux, organes génitaux, abdomen", "Catétère artériel systématique (monitoring continu PA + GDS perop)", "Monitoring neurophysiologique : PES et PEM pour détecter ischémie médullaire en temps réel", "Cell salvage si > 2 niveaux ou ré-intervention", "Acide tranexamique : 1g IV avant incision + 1g perfusion (réduction saignement 30-40%)", "Antibioprophylaxie : cefazoline 2g IV (répéter toutes les 4h si chirurgie longue)"], "postop": ["Analgésie multimodale : paracetamol + AINS (si pas de CI) + lidocaïne IV ou kétamine IV (anti-hyperalgésie)", "Morphine IV titrée ou PCA morphine si douleurs intenses", "Levée précoce J1 avec kinésithérapeute (protocole ERAS rachis)", "Thromboprophylaxie : bas de contention + HBPM dès J0 soir", "Surveillance neurologique : examen moteur/sensitif membres inférieurs toutes les heures × 6h"], "red_flags": ["Ischémie médullaire (changement PEM perop) : retirer instrumentations, élever PAM > 85 mmHg — urgence", "Hématome épidural postopératoire (déficit neurologique croissant) : IRM urgente + reprise chirurgicale < 6h", "Cécité postopératoire (POVL) : position DV + hypotension prolongée + anémie — risque neuropathie optique ischémique", "Saignement perop massif (multi-étagé) : activation protocole transfusion massive"], "drugs": [{"drug_id": "propofol", "indication_tag": "induction"}, {"drug_id": "rocuronium", "indication_tag": "intubation"}, {"drug_id": "sugammadex", "indication_tag": "reversal"}, {"drug_id": "sufentanil", "indication_tag": "analgesie_perop"}, {"drug_id": "remifentanil", "indication_tag": "TIVA_option"}, {"drug_id": "ketamine", "indication_tag": "anti-hyperalgesie"}, {"drug_id": "paracetamol", "indication_tag": "analgesie"}, {"drug_id": "acide_tranexamique", "indication_tag": "antifibrinolytique"}, {"drug_id": "noradrenaline", "indication_tag": "PAM_cible"}, {"drug_id": "cefazoline", "indication_tag": "antibioprophylaxie"}]}}, "deep": {"fr": {"clinical": ["La cécité postopératoire (POVL — posterior ischemic optic neuropathy) est une complication rare mais dévastatrice de la chirurgie rachidienne en DV : facteurs de risque = DV prolongé > 6h, hypotension, anémie sévère, obésité.", "Le monitoring neurophysiologique (PES + PEM) est standard pour les arthrodèses lombaires avec instrumentation — permet de détecter l''ischémie médullaire en temps réel.", "L''acide tranexamique réduit le saignement peropératoire de 30-40% dans la chirurgie du rachis.", "La PAM doit être maintenue > 80-85 mmHg en peropératoire pour assurer la perfusion médullaire."], "pitfalls": ["Position DV prolongée : vérifier les yeux toutes les 30 min (pression = POVL), protéger le visage sur repose-tête en mousse.", "ALIF : risque de lésion vasculaire (aorte, veine cave, iliaques) lors de la dissection antérieure — chirurgien vasculaire en stand-by recommandé.", "L''hypercapnie légère (PaCO2 40-45 mmHg) est préférable à l''hypocapnie — meilleure perfusion médullaire."], "references": [{"source": "North American Spine Society (NASS) — Lumbar Fusion", "year": 2022, "note": "Evidence-based guidelines"}, {"source": "SFAR — Rachis", "year": 2021, "note": "Recommandations anesthésie chirurgie rachidienne"}, {"source": "SRS — Scoliosis Research Society", "year": 2020, "note": "Neuromonitoring standards"}]}}}'::jsonb, false)
ON CONFLICT (id) DO UPDATE SET specialty=EXCLUDED.specialty, titles=EXCLUDED.titles, synonyms=EXCLUDED.synonyms, content=EXCLUDED.content, updated_at=now();
COMMIT;

